import React, { useState } from 'react'
import { Link } from 'react-router-dom'

export default function AddDecoPage(props) {
  const [errM, setErrM] = useState("")
  const [newItemName, setNewItemName] = useState("")
  let checkItem = (event) => {
    let i = event.target.value
    if (i.length > 1) {
      setErrM("")
      setNewItemName(i)
    }
    else {
      setErrM("please fill up a valid name for a product bigger than 1 letter")
    }
  }
  let addItem = () => {
    if (newItemName.length) {
      props.addNewDeco(props.name, newItemName)
    }
    else
      window.alert("invalid name product wasnt saved");

  }

return (
  <div>

    <h2>Add new item to the room</h2>
    <h2>Add Item</h2>
             <select name="items" id="items" onChange={checkItem}>
                <option value="chooseType">Choose room's type</option>
                <option value="Bedroom">Bedroom</option>
                <option value="Bathroom">Bathroom</option>
                <option value="Livingroom">LivingRoom</option>
                <option value="Kitchen">Kitchen</option>
            </select>

    <input type="text" onChange={checkItemName} placeholder='Please enter new Item name' maxLength="7" />
    <h4>{errM}</h4>

    <Link to={"/"}> <button onClick={addItem}>Add item</button></Link>
  </div>

)
}
